import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import './App.css';

const movies = [
  { id: 1, title: "Сны поездов", poster: "https://musicart.xboxlive.com/7/4d4d6500-0000-0000-0000-000000000002/504/image.jpg", price: 350 },
  { id: 2, title: "Интерстеллар", poster: "https://m.media-amazon.com/images/M/MV5BZjdkOTU3MDktN2IxOS00OGEyLWFmMjktY2FiMmZkNWIyODZiXkEyXkFqcGdeQXVyMTMxODk2OTU@._V1_.jpg", price: 400 },
  { id: 3, title: "Темный рыцарь", poster: "https://m.media-amazon.com/images/M/MV5BMTMxNTMwODM0NF5BMl5BanBnXkFtZTcwODAyMTk2Mw@@._V1_.jpg", price: 300 },
  { id: 4, title: "Джокер", poster: "https://m.media-amazon.com/images/M/MV5BNGVjNWI4ZGUtNzE0MS00YTJmLWE0ZDctN2ZiYTk2YmI3NTYyXkEyXkFqcGdeQXVyMTkxNjUyNQ@@._V1_.jpg", price: 450 },
];

function MainPage() {
  const navigate = useNavigate();

  const handleBuy = (movie) => {
    navigate('/create-order', { state: { movieTitle: movie.title, moviePrice: movie.price } });
  };

  return (
    <div className="main-page">
      <h2>🔥 Популярные фильмы</h2>
      <div className="movie-list">
        {movies.map((movie) => (
          <div key={movie.id} className="movie-card">
            <img src={movie.poster} alt={movie.title} />
            <h3>{movie.title}</h3>
            <p>Цена: {movie.price} сом</p>
            <div className="card-buttons">
              <Link to={`/movie/${movie.id}`} className="more-btn">Подробнее</Link>
              <button onClick={() => handleBuy(movie)} className="buy-btn">Купить</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default MainPage;
